mapper.select:
SELECT id, operation_type AS operationType, operation_label AS operationLabel, amount, amount_display AS amountDisplay, currency, operation_date AS operationDate, operation_time AS operationTime, created_at AS createdAt FROM tb_user_capital_flow WHERE user_id = #{userId}
AND operation_type = #{query.tradeType}
AND DATE(operation_date) >= #{query.tradeStartTime}
AND DATE(operation_date) <= #{query.tradeEndTime}
ORDER BY operation_date DESC, created_at DESC
